```cpp
#include <unistd.h>
#include <iostream>
#include <cstdio>

int main() {
    int fd[2];
    pipe(fd);  // Create a pipe

    pid_t pid = fork();  // Fork a new process

    if (pid == -1) {
        std::cerr << "Fork failed" << std::endl;
        return 1;
    }

    if (pid == 0) {  // Child process
        close(fd[1]);  // Close write end in child
        dup2(fd[0], STDIN_FILENO);  // Redirect child's stdin to read end of pipe
        dup2(fd[0], STDOUT_FILENO); // Redirect child's stdout to read end of pipe
        close(fd[0]);  // Close read end
        execlp("/bin/cat", "cat", NULL);  // Execute cat to read from stdin
        perror("execlp");
        _exit(1);
    } else {  // Parent process
        close(fd[0]);  // Close read end in parent
        // Write to the write end of the pipe
        fprintf(fd[1], "Hello from parent process\n");
        fflush(fd[1]);
        close(fd[1]);
    }

    return 0;
}
```

This code creates a pipe, forks a new process, and connects the read end of the pipe to the child's standard input and output. The parent process writes to the write end of the pipe, and the child reads from it.

